468	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
469	/// Empty premise / conclusion groups are dropped; the info group is always kept
470	/// (matches the observed group structure). Each prem/concl group's cells share the
471	/// record wrap budget by the proportional allocation [`group_widths`]; the info
472	/// cell is its own single-cell group (budget 87). Cell text is wrapped (ragged
473	/// HughesPJ `fill`) and escaped by [`crate::doclayout::wrap_cell_dot`].
474	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
475	    let mut columns: Vec<Vec<Cell>> = Vec::new();
476	    if !spec.premises.is_empty() {
477	        columns.push(group_cells(&spec.premises, ports_prem));
478	    }
479	    // The info cell is its own single-cell group (full width), fed through the
480	    // faithful layout engine at [`FILL_WIDTH`].
481	    columns.push(vec![Cell::new(port_info, wrap_cell_dot(&spec.info, FILL_WIDTH as isize))]);
482	    if !spec.conclusions.is_empty() {
483	        columns.push(group_cells(&spec.conclusions, ports_concl));
484	    }
485	    Record {
486	        columns,
487	        fillcolor: spec.fillcolor.clone(),
488	        fontcolor: spec.fontcolor.clone(),
489	        role: Role(spec.role.clone()),
490	    }
491	}
