493	/// Shape features of one cell's flat text that enter the row-share model
494	/// (probe-derived, BEHAVIOR.md §3f round 9): `flat` = display width; `dtop` =
495	/// Σ over top-level tuple arguments of `2·elems − 4` (the width surplus of the
496	/// reference's internal right-nested-pair form of an n-tuple over its flattened
497	/// display); `sqa` = the cell is a fact with exactly one argument that is a
498	/// single-quoted constant (whose internal form drops the quotes).
499	struct CellShape {
500	    flat: usize,
501	    dtop: i64,
502	    sqa: bool,
503	}
504	
505	/// Split a term list at top-level `", "`, honoring nesting and quotes.
506	fn split_level(s: &str) -> Vec<&str> {
507	    let b: Vec<(usize, char)> = s.char_indices().collect();
508	    let mut parts = Vec::new();
509	    let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
510	    let mut i = 0;
511	    while i < b.len() {
512	        let (pos, c) = b[i];
513	        if inq {
514	            if c == '\'' {
515	                inq = false;
516	            }
517	        } else {
518	            match c {
519	                '\'' => inq = true,
520	                '(' | '<' | '[' => depth += 1,
521	                ')' | '>' | ']' => depth -= 1,
522	                ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
523	                    parts.push(&s[start..pos]);
524	                    start = b[i + 1].0 + 1;
525	                    i += 1;
526	                }
527	                _ => {}
528	            }
529	        }
530	        i += 1;
531	    }
532	    parts.push(&s[start..]);
533	    parts
534	}
535	
536	fn cell_shape(flat: &str) -> CellShape {
537	    let width = flat.chars().count();
538	    let mut dtop = 0i64;
539	    let mut sqa = false;
540	    if let Some(open) = flat.find("( ") {
541	        // a padded fact with at least one argument (`Name( )` has none)
542	        if flat.ends_with(" )")
543	            && open + 2 <= flat.len() - 2
544	            && !flat[..open].contains(['(', ')', '<', '>', ' ', ','])
545	        {
546	            let inner = &flat[open + 2..flat.len() - 2];
547	            let args = split_level(inner);
548	            for a in &args {
549	                let t = a.trim();
550	                if t.starts_with('<') && t.ends_with('>') {
551	                    let elems = split_level(&t[1..t.len() - 1]).len() as i64;
552	                    dtop += 2 * elems - 4;
553	                }
554	            }
555	            if args.len() == 1 {
556	                let a = args[0].trim();
557	                sqa = a.starts_with('\'')
558	                    && a.ends_with('\'')
559	                    && a.len() >= 2
560	                    && !a[1..a.len() - 1].contains('\'');
561	            }
562	        }
563	    }
564	    CellShape { flat: width, dtop, sqa }
565	}
