567	/// The per-cell fit **budgets** of one record group (all premises together, or
568	/// all conclusions together), from the cells' flat texts. Two probe-derived
569	/// layers (BEHAVIOR.md §3f, round 9; every parameter pinned by live probe
570	/// batteries — QUERIES.log Session 9):
571	///
572	/// **Trigger** (which cells wrap). Each cell occupies
573	/// `C_j = flat_j + dtop_j` columns of the row (`dtop` = the internal
574	/// pair-nested surplus of top-level tuple args, `2n − 4` each); cell *i*'s
575	/// trigger budget is `max(87 [+ 4 if cell i has a tuple arg with ≥ 3 elems and
576	/// the row has ≥ 2 cells] − Σ_{j≠i} C_j, 20)`, and it wraps iff its effective
577	/// width exceeds that budget — the effective width is `flat`, except that a
578	/// single-quoted-atom fact above the floor measures `flat − 2` (its internal
579	/// form drops the quotes). Exact on 343/343 probe cells across three live
580	/// batteries; on the corpus it beats the round-6 flat-sum trigger (1.05 % vs
581	/// 1.45 % cell error), with the residual dominated by cells whose widths the
582	/// reference computes on the UN-abbreviated term (invisible here).
583	///
584	/// **Fill** (the ribbon a wrapping cell is laid out at):
585	/// `max(round(87·flat_i / (flat_i + Σ_{j≠i} w_j·flat_j)), 20)` — proportional
586	/// over display flats, with single-quoted-atom siblings discounted `w_j = 5/6`
587	/// (probed: the [Big 87, atom s] fill follows 87²/(87 + 5s/6) across
588	/// s = 12…120 with no saturation). Clamped below the cell's flat (a
589	/// trigger-wrapped cell must actually break). A fitting cell keeps
590	/// `max(trigger, flat)` so it renders flat; a lone cell's budget is exactly 87
591	/// (no bonus — the probed single-cell boundary).
592	pub fn group_widths(cells: &[String]) -> Vec<usize> {
593	    let shapes: Vec<CellShape> = cells.iter().map(|t| cell_shape(t)).collect();
594	    let n = shapes.len();
595	    let full = FILL_WIDTH as i64; // 87
596	    let cs: Vec<i64> = shapes.iter().map(|s| s.flat as i64 + s.dtop).collect();
597	    let ctot: i64 = cs.iter().sum();
598	    let mut out = Vec::with_capacity(n);
599	    for (i, sh) in shapes.iter().enumerate() {
600	        let flat = sh.flat as i64;
601	        if n == 1 {
602	            out.push(full as usize);
603	            continue;
604	        }
605	        let bonus = if sh.dtop > 0 { 4 } else { 0 };
606	        let b_trig = (full + bonus - (ctot - cs[i])).max(MIN_CELL_BUDGET as i64);
607	        let eff = if sh.sqa && b_trig > MIN_CELL_BUDGET as i64 { flat - 2 } else { flat };
608	        if eff <= b_trig {
609	            // fits: any budget ≥ flat renders the cell flat
610	            out.push(b_trig.max(flat) as usize);
611	            continue;
612	        }
613	        // wraps: proportional fill share (siblings at display flat, single-
614	        // quoted-atom siblings discounted 5/6)
615	        let mut t = flat as f64;
616	        for j in 0..n {
617	            if j != i {
618	                let w = if shapes[j].sqa { 5.0 / 6.0 } else { 1.0 };
619	                t += w * shapes[j].flat as f64;
620	            }
621	        }
622	        let mut b = ((full as f64) * (flat as f64) / t + 0.5).floor() as i64;
623	        b = b.max(MIN_CELL_BUDGET as i64).min((flat - 1).max(MIN_CELL_BUDGET as i64));
624	        out.push(b as usize);
625	    }
626	    out
627	}
