629	/// Wrap every cell of one record group, sharing the row via [`group_widths`]
630	/// and laying each cell out at its budget with the faithful engine.
631	fn group_cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
632	    let fills = group_widths(flat_cells);
633	    flat_cells
634	        .iter()
635	        .zip(ports)
636	        .zip(fills)
637	        .map(|((text, p), w)| Cell::new(p.clone(), wrap_cell_dot(text, w as isize)))
638	        .collect()
639	}
