88	/// Smallest L (line length at ribbons 1.5) whose ribbon >= flat.
89	fn fit_l(flat: usize) -> isize {
90	    let mut l = ((flat as f64) * 1.5).floor() as isize - 2;
91	    if l < 8 {
92	        l = 8;
93	    }
94	    loop {
95	        // banker's round of L/1.5, as the engine computes the ribbon
96	        let v = l as f64 / 1.5;
97	        let fl = v.floor();
98	        let r = if (v - fl - 0.5).abs() < 1e-9 {
99	            let f = fl as i64;
100	            if f % 2 == 0 {
101	                f
102	            } else {
103	                f + 1
104	            }
105	        } else {
106	            v.round() as i64
107	        };
108	        if r >= flat as i64 {
109	            return l;
110	        }
111	        l += 1;
112	    }
113	}
