115	/// STATUS string for one cell (see module docs).
116	fn cell_status(flat_text: &str, body: &str, flat: usize) -> String {
117	    let wraps = body.contains("\\l");
118	    if !wraps {
119	        // valid L set is [lo, +inf) (monotone: below the fit boundary the doc
120	        // wraps, above it renders flat; an unbreakable atom matches everywhere)
121	        let hi = fit_l(flat) + 2;
122	        let matches = |l: isize| wrap_cell_dot_lr(flat_text, l, 1.5) == body;
123	        if matches(8) {
124	            return "F8".to_string();
125	        }
126	        let (mut lo, mut hi) = (8isize, hi);
127	        // invariant: !matches(lo), matches(hi)
128	        if !matches(hi) {
129	            return "FNONE".to_string();
130	        }
131	        while hi - lo > 1 {
132	            let mid = (lo + hi) / 2;
133	            if matches(mid) {
134	                hi = mid;
135	            } else {
136	                lo = mid;
137	            }
138	        }
139	        return format!("F{}", hi);
140	    }
141	    // wrapping: sweep 8 ..= fitL (at/above fitL the render is one line != body)
142	    let top = fit_l(flat);
143	    let mut runs: Vec<(isize, isize)> = Vec::new();
144	    let mut cur: Option<(isize, isize)> = None;
145	    for l in 8..=top {
146	        if wrap_cell_dot_lr(flat_text, l, 1.5) == body {
147	            cur = Some(match cur {
148	                Some((a, _)) => (a, l),
149	                None => (l, l),
150	            });
151	        } else if let Some(r) = cur.take() {
152	            runs.push(r);
153	        }
154	    }
155	    if let Some(r) = cur {
156	        runs.push(r);
157	    }
158	    if runs.is_empty() {
159	        return "NONE".to_string();
160	    }
161	    runs.iter().map(|(a, b)| format!("{}-{}", a, b)).collect::<Vec<_>>().join(",")
162	}
