164	/// Shape features of a cell's flat text, for occupancy-model fitting:
165	/// `(dtop, drec, nq, sqa, nargs)` where `dtop` = Σ over TOP-LEVEL tuple args of
166	/// (2·elems − 4), `drec` = the same over ALL tuple nodes recursively, `nq` =
167	/// number of single-quoted constants anywhere, `sqa` = 1 if the cell is a fact
168	/// with exactly one argument that is a quoted constant, `nargs` = top-level
169	/// argument count (0 if the text is not a padded fact).
170	fn shape_features(flat: &str) -> (i64, i64, i64, i64, i64, i64, i64) {
171	    fn split_args(s: &str) -> Vec<&str> {
172	        let mut parts = Vec::new();
173	        let (mut depth, mut inq, mut start) = (0i32, false, 0usize);
174	        let b: Vec<(usize, char)> = s.char_indices().collect();
175	        let mut i = 0;
176	        while i < b.len() {
177	            let (pos, c) = b[i];
178	            if inq {
179	                if c == '\'' {
180	                    inq = false;
181	                }
182	            } else {
183	                match c {
184	                    '\'' => inq = true,
185	                    '(' | '<' | '[' => depth += 1,
186	                    ')' | '>' | ']' => depth -= 1,
187	                    ',' if depth == 0 && i + 1 < b.len() && b[i + 1].1 == ' ' => {
188	                        parts.push(&s[start..pos]);
189	                        start = b[i + 1].0 + 1;
190	                        i += 1;
191	                    }
192	                    _ => {}
193	                }
194	            }
195	            i += 1;
196	        }
197	        parts.push(&s[start..]);
198	        parts
199	    }
200	    fn tuple_nodes(s: &str, top: bool, dtop: &mut i64, drec: &mut i64) {
201	        let t = s.trim();
202	        if t.starts_with('<') && t.ends_with('>') {
203	            let inner = &t[1..t.len() - 1];
204	            let elems = split_args(inner);
205	            let d = 2 * elems.len() as i64 - 4;
206	            *drec += d;
207	            if top {
208	                *dtop += d;
209	            }
210	            for e in elems {
211	                tuple_nodes(e, false, dtop, drec);
212	            }
213	        } else if let Some(open) = t.find('(') {
214	            if t.ends_with(')') {
215	                let inner = &t[open + 1..t.len() - 1];
216	                let inner = inner.strip_prefix(' ').unwrap_or(inner);
217	                let inner = inner.strip_suffix(' ').unwrap_or(inner);
218	                for a in split_args(inner) {
219	                    tuple_nodes(a, false, dtop, drec);
220	                }
221	            }
222	        }
223	    }
224	    let nq = flat.split('\'').count() as i64 / 2;
225	    let (mut dtop, mut drec) = (0i64, 0i64);
226	    let mut nargs = 0i64;
227	    let mut sqa = 0i64;
228	    // function-application nodes inside the fact (name directly followed by
229	    // '(' with no ' ' after — the unpadded display form), e.g. senc(, pk(
230	    let nfunc = {
231	        let b: Vec<char> = flat.chars().collect();
232	        let mut n = 0i64;
233	        for i in 1..b.len() {
234	            if b[i] == '('
235	                && (b[i - 1].is_alphanumeric() || b[i - 1] == '_')
236	                && (i + 1 >= b.len() || b[i + 1] != ' ')
237	            {
238	                n += 1;
239	            }
240	        }
241	        n
242	    };
243	    // abbreviation-name tokens (2 uppercase letters + digits, e.g. KD19, EX1)
244	    let nabbr = {
245	        let b: Vec<char> = flat.chars().collect();
246	        let mut n = 0i64;
247	        let mut i = 0;
248	        while i < b.len() {
249	            if b[i].is_ascii_uppercase()
250	                && (i == 0 || !(b[i - 1].is_alphanumeric() || b[i - 1] == '_'))
251	            {
252	                let mut j = i + 1;
253	                while j < b.len() && b[j].is_ascii_uppercase() {
254	                    j += 1;
255	                }
256	                let letters = j - i;
257	                let ds = j;
258	                while j < b.len() && b[j].is_ascii_digit() {
259	                    j += 1;
260	                }
261	                if letters <= 2 && j > ds && (j >= b.len() || !(b[j].is_alphanumeric() || b[j] == '_')) {
262	                    n += 1;
263	                }
264	                i = j;
265	            } else {
266	                i += 1;
267	            }
268	        }
269	        n
270	    };
271	    if let Some(open) = flat.find("( ") {
272	        if flat.ends_with(" )") {
273	            let name = &flat[..open];
274	            if !name.is_empty() && !name.contains(['(', ')', '<', '>', ' ', ',']) {
275	                let inner = &flat[open + 2..flat.len() - 2];
276	                let args = split_args(inner);
277	                nargs = args.len() as i64;
278	                for a in &args {
279	                    tuple_nodes(a, true, &mut dtop, &mut drec);
280	                }
281	                if args.len() == 1 {
282	                    let a = args[0].trim();
283	                    if a.starts_with('\'') && a.ends_with('\'') && a.len() >= 2
284	                        && !a[1..a.len() - 1].contains('\'')
285	                    {
286	                        sqa = 1;
287	                    }
288	                }
289	            }
290	        }
291	    }
292	    (dtop, drec, nq, sqa, nargs, nfunc, nabbr)
293	}
