295	fn process_file(path: &std::path::Path, cache: &mut HashMap<(String, String), String>) -> Vec<String> {
296	    let mut out = Vec::new();
297	    let Ok(dot) = std::fs::read_to_string(path) else { return out };
298	    let base = path.file_name().unwrap().to_string_lossy().to_string();
299	    for line in dot.lines() {
300	        if !line.contains("shape=\"record\"") {
301	            continue;
302	        }
303	        let Some(ls) = line.find("label=\"") else { continue };
304	        let after = &line[ls + 7..];
305	        let Some(le) = after.find("\",fillcolor") else { continue };
306	        let Some(groups) = parse_record(&after[..le]) else { continue };
307	        // locate the info group; groups before = P, after = C
308	        let mut info_idx = None;
309	        let mut info_flat = 0usize;
310	        for (gi, cells) in groups.iter().enumerate() {
311	            if cells.len() == 1 {
312	                if let Some(b) = strip_port(&cells[0]) {
313	                    if is_info_body(b) {
314	                        info_idx = Some(gi);
315	                        info_flat = flat_width(b);
316	                    }
317	                }
318	            }
319	        }
320	        let Some(info_idx) = info_idx else { continue };
321	        let group_flats: Vec<Option<Vec<usize>>> = groups
322	            .iter()
323	            .map(|cells| {
324	                cells
325	                    .iter()
326	                    .map(|c| strip_port(c).map(flat_width))
327	                    .collect::<Option<Vec<usize>>>()
328	            })
329	            .collect();
330	        let flats_str = |gi: usize| -> String {
331	            if gi >= groups.len() {
332	                return String::new();
333	            }
334	            match &group_flats[gi] {
335	                Some(v) => v.iter().map(|f| f.to_string()).collect::<Vec<_>>().join(","),
336	                None => String::new(),
337	            }
338	        };
339	        // premise group (if any) is the group before info; conclusion after
340	        let prem_gi = if info_idx > 0 { Some(info_idx - 1) } else { None };
341	        let concl_gi = if info_idx + 1 < groups.len() { Some(info_idx + 1) } else { None };
342	        for (kind, gi) in [("P", prem_gi), ("C", concl_gi)] {
343	            let Some(gi) = gi else { continue };
344	            let cells = &groups[gi];
345	            let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
346	                Some(b) => b,
347	                None => continue,
348	            };
349	            if bodies.iter().any(|b| is_info_body(b)) {
350	                continue;
351	            }
352	            let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
353	            let total: usize = flats.iter().sum();
354	            let any_wrap = bodies.iter().any(|b| b.contains("\\l"));
355	            let dump = if bodies.len() >= 2 {
356	                any_wrap || total > 80
357	            } else {
358	                any_wrap
359	            };
360	            if !dump {
361	                continue;
362	            }
363	            let mut cellfields = Vec::with_capacity(bodies.len());
364	            for (k, body) in bodies.iter().enumerate() {
365	                let flat_text = dewrap(body);
366	                let key = (flat_text.clone(), body.to_string());
367	                let status = if let Some(s) = cache.get(&key) {
368	                    s.clone()
369	                } else {
370	                    let s = cell_status(&flat_text, body, flats[k]);
371	                    cache.insert(key, s.clone());
372	                    s
373	                };
374	                let (dtop, drec, nq, sqa, nargs, nfunc, nabbr) = shape_features(&flat_text);
375	                cellfields.push(format!(
376	                    "{}:{}:{}:{}:{}:{}:{}:{}:{}",
377	                    flats[k], status, dtop, drec, nq, sqa, nargs, nfunc, nabbr
378	                ));
379	            }
380	            out.push(format!(
381	                "{}\t{}\t{}\t{}\t{}\t{}",
382	                base,
383	                kind,
384	                info_flat,
385	                prem_gi.map(flats_str).unwrap_or_default(),
386	                concl_gi.map(flats_str).unwrap_or_default(),
387	                cellfields.join("|")
388	            ));
389	        }
390	    }
391	    out
392	}
