394	fn main() {
395	    let dirs: Vec<String> = std::env::args().skip(1).collect();
396	    let mut files: Vec<std::path::PathBuf> = Vec::new();
397	    for d in &dirs {
398	        for e in std::fs::read_dir(d).unwrap() {
399	            let p = e.unwrap().path();
400	            if p.extension().and_then(|e| e.to_str()) == Some("dot") {
401	                files.push(p);
402	            }
403	        }
404	    }
405	    files.sort();
406	    let nthreads = 8usize;
407	    let chunks: Vec<Vec<std::path::PathBuf>> = (0..nthreads)
408	        .map(|t| files.iter().skip(t).step_by(nthreads).cloned().collect())
409	        .collect();
410	    let handles: Vec<_> = chunks
411	        .into_iter()
412	        .map(|chunk| {
413	            std::thread::spawn(move || {
414	                let mut cache = HashMap::new();
415	                let mut out = Vec::new();
416	                for p in chunk {
417	                    out.extend(process_file(&p, &mut cache));
418	                }
419	                out
420	            })
421	        })
422	        .collect();
423	    let mut all = Vec::new();
424	    for h in handles {
425	        all.extend(h.join().unwrap());
426	    }
427	    all.sort();
428	    let mut so = String::new();
429	    for l in all {
430	        so.push_str(&l);
431	        so.push('\n');
432	    }
433	    print!("{}", so);
434	}
