111	/// Count top-level actions in an info action list `#t : Rule[ … ]` (0 if none).
112	pub fn count_info_actions(flat: &str) -> usize {
113	    let Some(open) = flat.find('[') else { return 0 };
114	    let inner = &flat[open + 1..];
115	    let inner = inner.strip_suffix(']').unwrap_or(inner);
116	    if inner.is_empty() {
117	        return 0;
118	    }
119	    split_top_commas(inner).len()
120	}
121	
122	fn is_tuple(s: &str) -> bool {
123	    s.starts_with('<') && s.ends_with('>') && s.len() >= 2
124	}
125	
126	/// A `Doc` for one tuple element / fact argument. Tuples recurse; every other
127	/// shape (atom, function application, exponentiation, AC term) is a single fill
128	/// token rendered from its flat text (these do not re-wrap internally in the
129	/// observed cells — the wrap happens at the enclosing fact/tuple level).
130	fn arg_doc(s: &str) -> Doc {
131	    if is_tuple(s) {
132	        tuple_doc(&s[1..s.len() - 1])
133	    } else {
134	        text(s)
135	    }
136	}
137	
138	/// `<e1, …, en>` — the elements fill and align one past the `<`; the `>` is a
139	/// fill element nested back one column so it stays beside the last element when
140	/// it fits and peels under the `<` otherwise.
141	fn tuple_doc(inner: &str) -> Doc {
142	    let elems = split_top_commas(inner);
143	    let n = elems.len();
144	    let mut toks: Vec<Doc> = Vec::with_capacity(n + 1);
145	    for (i, e) in elems.iter().enumerate() {
146	        let d = arg_doc(e);
147	        if i + 1 < n {
148	            toks.push(beside_op(d, text(", ")));
149	        } else {
150	            toks.push(d);
151	        }
152	    }
153	    toks.push(nest(-1, &pchar('>')));
154	    beside_op(pchar('<'), fcat(toks))
155	}
156	
157	/// `Name( a, b, … )` — the argument list is a comma-punctuated `fsep` opening
158	/// after `Name( `; the outer `sep [ …, ) ]` drops the closing `)` to its own line
159	/// exactly when the argument fill wraps.
160	fn fact_doc(name: &str, args: &[String]) -> Doc {
161	    if args.is_empty() {
162	        return text(&format!("{}( )", name));
163	    }
164	    let n = args.len();
165	    let toks: Vec<Doc> = args
166	        .iter()
167	        .enumerate()
168	        .map(|(i, a)| {
169	            let d = arg_doc(a);
170	            if i + 1 < n {
171	                beside_op(d, text(","))
172	            } else {
173	                d
174	            }
175	        })
176	        .collect();
177	    let args_doc = fsep(toks);
178	    let opened = beside_op(text(&format!("{}( ", name)), args_doc);
179	    sep(vec![opened, text(")")])
180	}
181	
182	/// `#t : Rule[a1, …]` — the action list is a `vcat` (one action per line) inside
183	/// `[ … ]`; `#t : Rule` with no actions is bare text.
184	fn info_doc(flat: &str) -> Doc {
185	    let Some(open) = flat.find('[') else {
186	        return text(flat);
187	    };
188	    if !flat.ends_with(']') {
189	        return text(flat);
190	    }
191	    let prefix = &flat[..open + 1]; // "#t : Rule["
192	    let inner = &flat[open + 1..flat.len() - 1];
193	    let actions = split_top_commas(inner);
194	    let n = actions.len();
195	    let action_docs: Vec<Doc> = actions
196	        .iter()
197	        .enumerate()
198	        .map(|(i, a)| {
199	            // Each action is a fact that may itself fill-wrap; non-final actions
200	            // carry a trailing comma.
201	            let d = fact_from_flat(a);
202	            if i + 1 < n {
203	                beside_op(d, text(","))
204	            } else {
205	                d
206	            }
207	        })
208	        .collect();
209	    beside_op(beside_op(text(prefix), vcat(action_docs)), text("]"))
210	}
211	
212	/// Build a fact `Doc` from a flat fact string `Name( … )` (or a bare atom).
213	fn fact_from_flat(flat: &str) -> Doc {
214	    if let Some((name, args)) = parse_fact(flat) {
215	        fact_doc(name, &args)
216	    } else {
217	        text(flat)
218	    }
219	}
220	
221	/// Parse a padded fact `Name( a, b )` / `Name( )` into `(name, args)`. Returns
222	/// `None` for anything that is not a padded fact (an atom, a function `f(x)`
223	/// without inner padding, etc.).
224	fn parse_fact(flat: &str) -> Option<(&str, Vec<String>)> {
225	    if flat == "" {
226	        return None;
227	    }
228	    // Zero-arg: "Name( )"
229	    if let Some(name) = flat.strip_suffix("( )") {
230	        if !name.is_empty() && !name.contains(['(', ')', '<', '>', ' ']) {
231	            return Some((name, Vec::new()));
232	        }
233	    }
234	    let open = flat.find("( ")?;
235	    if !flat.ends_with(" )") {
236	        return None;
237	    }
238	    let name = &flat[..open];
239	    // The name must be a plain relation/fact symbol (optionally `!`-prefixed).
240	    if name.is_empty()
241	        || name.contains(['(', ')', '<', '>', ' ', ','])
242	    {
243	        return None;
244	    }
245	    let content = &flat[open + 2..flat.len() - 2];
246	    Some((name, split_top_commas(content)))
247	}
248	
249	/// Build a `Doc` for one record cell from its flat (post-abbreviation,
250	/// un-escaped) text, dispatching by cell shape (info / fact / atom).
251	pub fn cell_doc(flat: &str) -> Doc {
252	    if flat.starts_with('#') && flat.contains('[') {
253	        info_doc(flat)
254	    } else if let Some((name, args)) = parse_fact(flat) {
255	        fact_doc(name, &args)
256	    } else {
257	        text(flat)
258	    }
259	}
