261	/// Render a cell's flat text to physical lines `(indent, content)` at the given
262	/// fit **budget** (ribbon), via the layout engine. `indent` is the count of
263	/// leading spaces the engine emitted (→ `&nbsp;` in the record label); `content`
264	/// is the line with that indentation stripped, still un-escaped. The cell fits on
265	/// one line iff its flat width ≤ `budget`; the line length is
266	/// [`budget_line_len`]`(budget)` (= 1.5·budget) so wrapping is ragged (§3f).
267	pub fn layout_lines(flat: &str, budget: isize) -> Vec<(usize, String)> {
268	    layout_lines_lr(flat, budget_line_len(budget), RIBBONS)
269	}
270	
271	/// Like [`layout_lines`] but with an explicit `line_len` and `ribbons_per_line`
272	/// (ribbon = round(line_len / ribbons_per_line)). When `line_len` exceeds the
273	/// ribbon, HughesPJ `fill` produces ragged paragraph fills (a physical line may
274	/// be shorter than a later one), the reference's observed behavior.
275	pub fn layout_lines_lr(flat: &str, line_len: isize, ribbons_per_line: f64) -> Vec<(usize, String)> {
276	    let doc = cell_doc(flat);
277	    let rendered = render_page(line_len, ribbons_per_line, &doc);
278	    rendered
279	        .split('\n')
280	        .map(|line| {
281	            let indent = line.len() - line.trim_start_matches(' ').len();
282	            (indent, line[indent..].to_string())
283	        })
284	        .collect()
285	}
286	
287	/// Like [`wrap_cell_dot`] but with an explicit line length and ribbons-per-line.
288	pub fn wrap_cell_dot_lr(flat: &str, line_len: isize, ribbons_per_line: f64) -> String {
289	    let lines = layout_lines_lr(flat, line_len, ribbons_per_line);
290	    if lines.len() == 1 && lines[0].0 == 0 {
291	        return crate::render::escape_record(&lines[0].1);
292	    }
293	    let mut out = String::new();
294	    for (indent, content) in &lines {
295	        out.push_str(&"&nbsp;".repeat(*indent));
296	        out.push_str(&crate::render::escape_record(content));
297	        out.push_str("\\l");
298	    }
299	    out
300	}
301	
302	/// Render a cell's flat text into the exact graphviz record-label bytes at the
303	/// given fit **budget** (ribbon): a single escaped line when the flat width ≤
304	/// `budget`, otherwise each physical line prefixed by its `&nbsp;` indent,
305	/// escaped, and terminated by `\l` (trailing `\l` included), per BEHAVIOR.md §3f.
306	/// The layout is computed on the UN-escaped text (so `<`/`>` count one column
307	/// each, matching the reference), and escaping is applied afterwards. Wrapping is
308	/// ragged (line length = 1.5·budget; see [`RIBBONS`]).
309	pub fn wrap_cell_dot(flat: &str, budget: isize) -> String {
310	    let lines = layout_lines(flat, budget);
311	    if lines.len() == 1 && lines[0].0 == 0 {
312	        return crate::render::escape_record(&lines[0].1);
313	    }
314	    let mut out = String::new();
315	    for (indent, content) in &lines {
316	        out.push_str(&"&nbsp;".repeat(*indent));
317	        out.push_str(&crate::render::escape_record(content));
318	        out.push_str("\\l");
319	    }
320	    out
321	}
