    trig_err=fill_miss=trig_tot=fill_tot=0
    for path in sys.argv[1:]:
        for fname,cells in parse(path):
            preds=model(cells,own_d)
            for i,(c,(pw,L)) in enumerate(zip(cells,preds)):
