/// The per-cell fit **budgets** of one record group (all premises together, or
/// all conclusions together), from the cells' flat texts. Two probe-derived
/// layers (BEHAVIOR.md §3f, round 9; every parameter pinned by live probe
/// batteries — QUERIES.log Session 9):
///
/// **Trigger** (which cells wrap). Each cell occupies
/// `C_j = flat_j + dtop_j` columns of the row (`dtop` = the internal
/// pair-nested surplus of top-level tuple args, `2n − 4` each); cell *i*'s
/// trigger budget is `max(87 [+ 4 if cell i has a tuple arg with ≥ 3 elems and
/// the row has ≥ 2 cells] − Σ_{j≠i} C_j, 20)`, and it wraps iff its flat width
/// exceeds that budget. There is NO single-quoted-atom width discount: the
/// round-10 audit battery (RA/RB/RC/RD/RE, QUERIES.log Session 10) refuted
/// both round-9 candidates (own `flat − 2`: 440/446 probe cells; sibling
/// occupancy `flat − 4`: refuted directly by the RA/RB X flips) — the plain
/// flat occupancy scores 443/446, and the sqa term never decides a corpus
/// cell (all variants corpus-identical, 1.09 % cell error vs 1.46 % for the
/// uncorrected flat-sum). The 3 residual probe cells (a `[45, 43]`-shaped sib
/// saved at budget+1 while `[46, 42]` / `[28, 28, 32]` sibs are not) are the
/// known ±1 coupled-`fits` boundary flip, not a shape correction.
///
/// **Fill** (the ribbon a wrapping cell is laid out at):
/// `max(round(87·flat_i / (flat_i + Σ_{j≠i} w_j·flat_j)), 20)` — proportional
/// over display flats. A single-quoted-atom sibling is discounted `w_j = 5/6`
/// ONLY when cell *i* is itself a tuple-fact (`dtop_i > 0`): the [Big 87,
/// atom s] fill follows 87²/(87 + 5s/6) across s = 12…120 (round-9 Q/I
/// series), but the round-10 RA/RB/RE argfact receivers track the plain
/// 87·f/(f+s) share (5/6 there overshoots by 2–4 columns). Composite score:
/// 351/362 probe fill bands, corpus banded-fill unchanged (82.17 %).
/// Clamped below the cell's flat (a trigger-wrapped cell must actually
/// break). A fitting cell keeps `max(trigger, flat)` so it renders flat; a
/// lone cell's budget is exactly 87 (no bonus — the probed single-cell
/// boundary).
pub fn group_widths(cells: &[String]) -> Vec<usize> {
    let shapes: Vec<CellShape> = cells.iter().map(|t| cell_shape(t)).collect();
    let n = shapes.len();
    let full = FILL_WIDTH as i64; // 87
    let cs: Vec<i64> = shapes.iter().map(|s| s.flat as i64 + s.dtop).collect();
    let ctot: i64 = cs.iter().sum();
    let mut out = Vec::with_capacity(n);
    for (i, sh) in shapes.iter().enumerate() {
        let flat = sh.flat as i64;
        if n == 1 {
            out.push(full as usize);
            continue;
        }
        let bonus = if sh.dtop > 0 { 4 } else { 0 };
        let b_trig = (full + bonus - (ctot - cs[i])).max(MIN_CELL_BUDGET as i64);
        if flat <= b_trig {
            // fits: any budget ≥ flat renders the cell flat
            out.push(b_trig.max(flat) as usize);
            continue;
        }
        // wraps: proportional fill share over display flats; single-quoted-atom
        // siblings are discounted 5/6 only for a tuple-fact receiver
        let mut t = flat as f64;
        for j in 0..n {
            if j != i {
                let w = if shapes[j].sqa && sh.dtop > 0 { 5.0 / 6.0 } else { 1.0 };
                t += w * shapes[j].flat as f64;
            }
        }
        let mut b = ((full as f64) * (flat as f64) / t + 0.5).floor() as i64;
        b = b.max(MIN_CELL_BUDGET as i64).min((flat - 1).max(MIN_CELL_BUDGET as i64));
        out.push(b as usize);
    }
    out
}

